export const DEMO_AUDIO_PATH = "/assets/demo-voice-message.mp3";
export const DEMO_AUDIO_URL = "https://veracityapi.com" + DEMO_AUDIO_PATH;
export const DEMO_AUDIO_TRANSCRIPT = "Hey you, I have been thinking about you all morning. I know we have not actually met yet, but honestly, I feel like I have known you forever. Work has been crazy this week, but I promise, when things settle down, you are the first person I want to see. Sweet dreams, okay?";

export function demoAudioBytes(): Uint8Array {
  const clean = DEMO_AUDIO_BASE64.replace(/\s/g, "");
  const binary = atob(clean);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  return bytes;
}
